function DocsCommandPalette() {
  const { div, input, span, kbd } = tags;
  const [isOpen, setIsOpen] = createSignal(false);
  const [query, setQuery] = createSignal('');
  const [activeIndex, setActiveIndex] = createSignal(0);

  const DOCS_INDEX = [
    { title: 'Quick Setup', section: 'Start Here', path: '/docs/quick-setup', icon: 'zap', keywords: ['install'] },
    { title: 'Adding Pages', section: 'Building', path: '/docs/building/pages', icon: 'file', keywords: ['page', 'route'] }
  ];

  const results = createMemo(() => {
    const q = query().toLowerCase();
    if (!q) return DOCS_INDEX;
    return DOCS_INDEX.filter(item =>
      item.title.toLowerCase().includes(q) ||
      item.section.toLowerCase().includes(q) ||
      item.keywords.some(k => k.includes(q))
    );
  });

  function selectItem(item) {
    setIsOpen(false);
    setQuery('');
    navigate(item.path);
  }

  function handleKeyDown(e) {
    if (!isOpen()) {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        setIsOpen(true);
      }
      return;
    }
    if (e.key === 'Escape') { setIsOpen(false); setQuery(''); }
    if (e.key === 'ArrowDown') setActiveIndex(i => Math.min(i + 1, results().length - 1));
    if (e.key === 'ArrowUp') setActiveIndex(i => Math.max(i - 1, 0));
    if (e.key === 'Enter' && results()[activeIndex()]) selectItem(results()[activeIndex()]);
  }

  document.addEventListener('keydown', handleKeyDown);
  onDestroy(() => document.removeEventListener('keydown', handleKeyDown));

  const overlay = div({ class: css('_fixed _inset0 _z[100] _bg[rgba(0,0,0,0.6)] _backdrop[blur(4px)] _flex _aic _jcc') });
  overlay.style.display = 'none';
  overlay.onclick = (e) => { if (e.target === overlay) { setIsOpen(false); setQuery(''); } };

  const container = div({ class: css('_w100 _maxw[560px] _bgbg _r2 _shadow _border _overflow[hidden] _flex _col') });
  // ... input, results rendering

  createEffect(() => { overlay.style.display = isOpen() ? 'flex' : 'none'; });

  overlay.appendChild(container);
  return overlay;
}
